		if (atombios_legacy_lvds_output_control(ctx, ATOM_LCD_BLOFF) ||
		    atombios_legacy_lvds_output_control(ctx, ATOM_DISABLE) ||
		    atombios_select_crtc_source(ctx, &paths[active_path], crtc_id) ||
		    atombios_set_pixel_clock(ctx, &paths[active_path],
					     pixel_clock_10khz, crtc_id))
			goto modeset_failed;

		if (atombios_set_crtc_dtd_timing(ctx, &mode, crtc_id))
			goto modeset_failed;
		atombios_program_framebuffer(ctx, &gpu, fb_bar, &mode);
		if (atombios_program_crtc_postmode(ctx, crtc_id) ||
		    atombios_enable_crtc(ctx, crtc_id, 1) ||
		    atombios_enable_crtc_mem_req(ctx, &gpu, crtc_id, 1) ||
		    atombios_legacy_lvds_encoder_setup(ctx, &paths[active_path],
						       pixel_clock_10khz, ATOM_ENABLE) ||
		    atombios_legacy_lvds_output_control(ctx, ATOM_ENABLE) ||
		    atombios_legacy_lvds_output_control(ctx, ATOM_LCD_BLON) ||
		    atombios_blank_crtc(ctx, crtc_id, 0))
			goto modeset_failed;
		atombios_evergreen_unblank_scanout(ctx, &gpu);
		atombios_update_scratch_for_path(ctx, &paths[active_path],
						 crtc_id, true, true);
		atombios_output_lock(ctx, false);
	} else if (paths[active_path].is_legacy_tmds) {
		/*
		 * Legacy DVI/TMDS output path (pre-UNIPHY).  Linux handles these
		 * with TMDSA/LVTMA encoder and output-control tables, not DIGx
		 * encoder or UNIPHY transmitter tables.
		 */
		printk(BIOS_INFO, "ATOMBIOS: DVI output via legacy TMDS encoder 0x%02x\n",
		       paths[active_path].encoder_obj_id);

		if (atombios_legacy_tmds_output_control(ctx, &paths[active_path],
							 ATOM_DISABLE) ||
		    atombios_select_crtc_source(ctx, &paths[active_path], crtc_id) ||
		    atombios_set_pixel_clock(ctx, &paths[active_path],
					     pixel_clock_10khz, crtc_id))
			goto modeset_failed;

		printk(BIOS_INFO, "ATOMBIOS: programming CRTC timing...\n");
		if (atombios_set_crtc_dtd_timing(ctx, &mode, crtc_id))
			goto modeset_failed;
		atombios_program_framebuffer(ctx, &gpu, fb_bar, &mode);
		if (atombios_program_crtc_postmode(ctx, crtc_id) ||
		    atombios_enable_crtc(ctx, crtc_id, 1) ||
		    atombios_enable_crtc_mem_req(ctx, &gpu, crtc_id, 1) ||
		    atombios_legacy_tmds_encoder_setup(ctx, &paths[active_path],
						       pixel_clock_10khz, ATOM_ENABLE) ||
		    atombios_legacy_tmds_output_control(ctx, &paths[active_path],
							 ATOM_ENABLE) ||
		    atombios_blank_crtc(ctx, crtc_id, 0))
			goto modeset_failed;
		atombios_evergreen_unblank_scanout(ctx, &gpu);
		atombios_update_scratch_for_path(ctx, &paths[active_path],
						 crtc_id, true, true);
		atombios_output_lock(ctx, false);
	} else {
		/*
		 * Digital output path: DIG encoder + UNIPHY transmitter.
		 */

		/* For eDP, power on the panel first */
		if (active_path >= 0 &&
		    paths[active_path].encoder_mode == ATOM_ENCODER_MODE_DP) {
			uint8_t conn_id = atombios_object_id(paths[active_path].connector_obj_id);
			if (conn_id == CONNECTOR_OBJECT_ID_eDP) {
				if (atombios_edp_panel_power(ctx, &paths[active_path], 1))
					goto modeset_failed;
				mdelay(200);
			}
		}

		if (atombios_dp_prepare_link(ctx, &paths[active_path], mode.pixel_clock))
			goto modeset_failed;

		/* Initialize transmitter PHY */
		if (active_path >= 0) {
			printk(BIOS_INFO, "ATOMBIOS: initializing transmitter PHY %d...\n",
			       paths[active_path].phy_id);
			if (atombios_transmitter_control(ctx, &paths[active_path],
							 pixel_clock_10khz,
							 ATOM_TRANSMITTER_ACTION_INIT,
							 0, 0))
				goto modeset_failed;
		}

		/* Configure DIG encoder */
		if (active_path >= 0) {
			printk(BIOS_INFO, "ATOMBIOS: configuring DIG encoder %d...\n",
			       paths[active_path].dig_encoder);
			if (atombios_dig_encoder_setup(ctx, &paths[active_path],
						       pixel_clock_10khz,
						       ATOM_ENCODER_CMD_SETUP,
						       PANEL_8BIT_PER_COLOR))
				goto modeset_failed;
			if (paths[active_path].encoder_mode == ATOM_ENCODER_MODE_DP &&
			    atombios_object_id(paths[active_path].connector_obj_id) ==
				CONNECTOR_OBJECT_ID_eDP &&
			    atombios_dig_encoder_setup(ctx, &paths[active_path],
						       pixel_clock_10khz,
						       ATOM_ENCODER_CMD_SETUP_PANEL_MODE,
						       PANEL_8BIT_PER_COLOR))
				goto modeset_failed;
		}

		/* Route CRTC to encoder and program its pixel clock. */
		if (atombios_select_crtc_source(ctx, &paths[active_path], crtc_id) ||
		    atombios_set_pixel_clock(ctx, &paths[active_path],
					     pixel_clock_10khz, crtc_id))
			goto modeset_failed;

		/* Program CRTC timing and scanout state. */
		printk(BIOS_INFO, "ATOMBIOS: programming CRTC timing...\n");
		if (atombios_set_crtc_dtd_timing(ctx, &mode, crtc_id))
			goto modeset_failed;
		atombios_program_framebuffer(ctx, &gpu, fb_bar, &mode);
		if (atombios_program_crtc_postmode(ctx, crtc_id) ||
		    atombios_enable_crtc(ctx, crtc_id, 1) ||
		    atombios_enable_crtc_mem_req(ctx, &gpu, crtc_id, 1))
			goto modeset_failed;

		/* Enable transmitter */
		printk(BIOS_INFO, "ATOMBIOS: enabling transmitter...\n");
		if (atombios_transmitter_control(ctx, &paths[active_path],
						 pixel_clock_10khz,
						 ATOM_TRANSMITTER_ACTION_ENABLE,
						 0, 0))
			goto modeset_failed;

		/* DP link training */
		if (active_path >= 0 &&
		    paths[active_path].encoder_mode == ATOM_ENCODER_MODE_DP) {
			printk(BIOS_INFO, "ATOMBIOS: starting DP link training...\n");
			if (atombios_dp_link_train(ctx, &paths[active_path],
						   pixel_clock_10khz,
						   paths[active_path].i2c_line,
						   paths[active_path].hpd_id))
				goto modeset_failed;
			if (atombios_object_id(paths[active_path].connector_obj_id) ==
			    CONNECTOR_OBJECT_ID_eDP &&
			    atombios_transmitter_control(ctx, &paths[active_path],
							pixel_clock_10khz,
							ATOM_TRANSMITTER_ACTION_LCD_BLON,
							0, 0))
				goto modeset_failed;
		}

		/* Unblank */
		if (atombios_blank_crtc(ctx, crtc_id, 0))
			goto modeset_failed;
		atombios_evergreen_unblank_scanout(ctx, &gpu);
		atombios_update_scratch_for_path(ctx, &paths[active_path],
						 crtc_id, true, true);
		atombios_output_lock(ctx, false);
	}

	/* Register framebuffer with coreboot */
	fb_add_framebuffer_info(fb_bar,
				mode.ha, mode.va,
				mode.ha * BYTES_PER_PIXEL,
				DEFAULT_BPP);

	printk(BIOS_INFO, "ATOMBIOS: framebuffer %ux%u @ 0x%llx registered\n",
	       mode.ha, mode.va, (unsigned long long)fb_bar);
	return;

modeset_failed:
	printk(BIOS_ERR, "ATOMBIOS: modeset failed; framebuffer not registered\n");
	atombios_output_lock(ctx, false);
	atom_destroy(ctx);
}

